const groqResult = $input.item.json;
const originalLead = $('Handle Scrape Fallback').item.json;

function getTimestamp() {
  const now = new Date();
  const pad = (num) => String(num).padStart(2, '0');
  return `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())} ${pad(now.getHours())}:${pad(now.getMinutes())}:${pad(now.getSeconds())}`;
}

let aiContent = {};
try {
  // Extract content string from Groq payload
  let rawContent = groqResult.choices[0].message.content;

  // Clean markdown wrapper backticks if present
  rawContent = rawContent.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();

  aiContent = JSON.parse(rawContent);
} catch (e) {
  console.error("Failed to parse Groq AI response:", e);
  // Fallback object in case of complete parsing failure
  aiContent = {
    companyName: originalLead.title.split(' ')[0] || 'Unknown',
    founders: null,
    businessEvent: 'Parsing Error: AI response was not valid JSON',
    companyStage: null,
    recommendedServices: [],
    confidence: 1,
    leadQuality: 'Low',
    qualificationReason: 'Complete parser error on AI output. Review execution logs.',
    riskFactors: [],
    nextAdvisoryOpportunity: 'Manual review required'
  };
}

// Standardize keys and fallback values
const companyName = aiContent.companyName || originalLead.title.split(' ')[0] || 'Unknown';
const founders = Array.isArray(aiContent.founders) ? aiContent.founders.join(', ') : (aiContent.founders || 'Unknown');
const businessEvent = aiContent.businessEvent || originalLead.description || 'Unknown event';
const companyStage = aiContent.companyStage || 'Unknown';
const recommendedServices = Array.isArray(aiContent.recommendedServices) ? aiContent.recommendedServices.join(', ') : (aiContent.recommendedServices || 'General Consulting');
const confidence = typeof aiContent.confidence === 'number' ? aiContent.confidence : parseInt(aiContent.confidence) || 5;
const leadQuality = aiContent.leadQuality || (confidence >= 7 ? 'High' : (confidence >= 4 ? 'Medium' : 'Low'));
const qualificationReason = aiContent.qualificationReason || 'No reasoning provided by AI.';
const riskFactors = Array.isArray(aiContent.riskFactors) ? aiContent.riskFactors.join(', ') : (aiContent.riskFactors || 'None');
const nextAdvisoryOpportunity = aiContent.nextAdvisoryOpportunity || 'General consultation';

// Output standard mapped contract matching Google Sheets column structure
return [{
  json: {
    companyName: companyName,
    founders: founders,
    businessEvent: businessEvent,
    companyStage: companyStage,
    recommendedServices: recommendedServices,
    leadQuality: leadQuality,
    confidence: confidence,
    qualificationReason: qualificationReason,
    riskFactors: riskFactors,
    nextAdvisoryOpportunity: nextAdvisoryOpportunity,
    articleDate: originalLead.articleDate || aiContent.articleDate || 'Unknown',
    sourceUrl: originalLead.sourceUrl,
    processedTimestamp: getTimestamp()
  }
}];
